import { useState } from 'react';
import { Zap, Plus, Trash2 } from 'lucide-react';

interface Story {
  title: string;
  description: string;
  acceptanceCriteria: string[];
}

interface StoriesTabProps {
  projectId: string;
  designDocContent: string;
  onStoriesGenerated?: (stories: Story[]) => void;
}

export function StoriesTab({ projectId, designDocContent, onStoriesGenerated }: StoriesTabProps) {
  const [stories, setStories] = useState<Story[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [expandedStory, setExpandedStory] = useState<number | null>(null);

  const handleGenerateStories = async () => {
    if (!designDocContent) {
      setError('Please generate a design document first');
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const response = await fetch(`/api/projects/${projectId}/stories`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          designDoc: designDocContent,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to generate stories');
      }

      const data = await response.json();
      setStories(data.stories || []);
      onStoriesGenerated?.(data.stories);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
      console.error('Story generation error:', err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRemoveStory = (index: number) => {
    setStories(stories.filter((_, i) => i !== index));
  };

  const handleAddStory = () => {
    const newStory: Story = {
      title: 'New Story',
      description: '',
      acceptanceCriteria: [''],
    };
    setStories([...stories, newStory]);
  };

  if (stories.length === 0 && !isGenerating) {
    return (
      <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96 flex flex-col items-center justify-center">
        <div className="text-4xl mb-4"></div>
        <h3 className="text-lg font-semibold text-white mb-2">Generate User Stories</h3>
        <p className="text-slate-400 text-center mb-6">
          Use Grok's reasoning model to automatically generate user stories from your design document
        </p>
        {error && (
          <div className="bg-red-900/30 border border-red-800 rounded-lg p-3 mb-6 w-full">
            <p className="text-red-400 text-sm">{error}</p>
          </div>
        )}
        <button
          onClick={handleGenerateStories}
          disabled={!designDocContent}
          className="px-8 py-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white font-medium rounded-full hover:from-blue-500 hover:to-blue-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
        >
          <Zap size={18} />
          Generate Stories from Design Doc
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold text-white">User Stories ({stories.length})</h3>
        <div className="flex gap-3">
          <button
            onClick={handleAddStory}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center gap-2"
          >
            <Plus size={18} />
            Add Story
          </button>
          <button
            onClick={handleGenerateStories}
            disabled={isGenerating || !designDocContent}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center gap-2"
          >
            {isGenerating ? (
              <>
                <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div>
                Generating...
              </>
            ) : (
              <>
                <Zap size={18} />
                Regenerate
              </>
            )}
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-900/30 border border-red-800 rounded-lg p-4">
          <p className="text-red-400 text-sm">{error}</p>
        </div>
      )}

      <div className="space-y-4">
        {stories.map((story, index) => (
          <div
            key={index}
            className="bg-slate-700 border border-slate-600 rounded-lg overflow-hidden"
          >
            <button
              onClick={() => setExpandedStory(expandedStory === index ? null : index)}
              className="w-full px-6 py-4 text-left hover:bg-slate-600/50 transition-colors flex justify-between items-center"
            >
              <div>
                <h4 className="font-semibold text-white">{story.title}</h4>
                <p className="text-sm text-slate-300 mt-1 line-clamp-2">{story.description}</p>
              </div>
              <div className="text-2xl">
                {expandedStory === index ? '▼' : '▶'}
              </div>
            </button>

            {expandedStory === index && (
              <div className="border-t border-slate-600 px-6 py-4 bg-slate-800 space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-300 mb-2">
                    Description
                  </label>
                  <textarea
                    value={story.description}
                    onChange={(e) => {
                      const updated = [...stories];
                      updated[index].description = e.target.value;
                      setStories(updated);
                    }}
                    className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows={3}
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-300 mb-2">
                    Acceptance Criteria
                  </label>
                  <div className="space-y-2">
                    {story.acceptanceCriteria.map((criterion, idx) => (
                      <input
                        key={idx}
                        type="text"
                        value={criterion}
                        onChange={(e) => {
                          const updated = [...stories];
                          updated[index].acceptanceCriteria[idx] = e.target.value;
                          setStories(updated);
                        }}
                        placeholder={`Criterion ${idx + 1}`}
                        className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    ))}
                    <button
                      onClick={() => {
                        const updated = [...stories];
                        updated[index].acceptanceCriteria.push('');
                        setStories(updated);
                      }}
                      className="text-sm text-blue-400 hover:text-blue-300"
                    >
                      + Add Criterion
                    </button>
                  </div>
                </div>

                <div className="flex justify-end">
                  <button
                    onClick={() => handleRemoveStory(index)}
                    className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 transition-colors flex items-center gap-2"
                  >
                    <Trash2 size={16} />
                    Remove Story
                  </button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Zap, Plus, Trash2 } from 'lucide-react';

interface Story {
  title: string;
  description: string;
  acceptanceCriteria: string[];
}

interface StoriesTabProps {
  projectId: string;
  designDocContent: string;
  onStoriesGenerated?: (stories: Story[]) => void;
}

export function StoriesTab({ projectId, designDocContent, onStoriesGenerated }: StoriesTabProps) {
  const [stories, setStories] = useState<Story[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [expandedStory, setExpandedStory] = useState<number | null>(null);

  const handleGenerateStories = async () => {
    if (!designDocContent) {
      setError('Please generate a design document first');
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const response = await fetch(`/api/projects/${projectId}/stories`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          designDoc: designDocContent,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to generate stories');
      }

      const data = await response.json();
      const newStories = data.stories || [];

      // Append new stories instead of replacing
      setStories([...stories, ...newStories]);
      onStoriesGenerated?.([...stories, ...newStories]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
      console.error('Story generation error:', err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRemoveStory = (index: number) => {
    setStories(stories.filter((_, i) => i !== index));
  };

  const handleAddStory = () => {
    const newStory: Story = {
      title: 'New Story',
      description: '',
      acceptanceCriteria: [''],
    };
    setStories([...stories, newStory]);
  };

  if (stories.length === 0 && !isGenerating) {
    return (
      <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 min-h-96 flex flex-col items-center justify-center">
        <div className="text-4xl mb-4"></div>
        <h3 className="text-lg font-semibold text-white mb-2">Generate User Stories</h3>
        <p className="text-slate-400 text-center mb-6">
          Use Grok's reasoning model to automatically generate user stories from your design document
        </p>
        {error && (
          <div className="bg-red-900/30 border border-red-800 rounded-lg p-3 mb-6 w-full">
            <p className="text-red-400 text-sm">{error}</p>
          </div>
        )}
        <button
          onClick={handleGenerateStories}
          disabled={!designDocContent}
          className="px-8 py-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white font-medium rounded-full hover:from-blue-500 hover:to-blue-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
        >
          <Zap size={18} />
          Generate Stories from Design Doc
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold text-white">User Stories ({stories.length})</h3>
        <div className="flex gap-3">
          <button
            onClick={handleAddStory}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center gap-2"
          >
            <Plus size={18} />
            Add Story
          </button>
          <button
            onClick={handleGenerateStories}
            disabled={isGenerating || !designDocContent}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center gap-2"
          >
            {isGenerating ? (
              <>
                <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div>
                Generating...
              </>
            ) : (
              <>
                <Zap size={18} />
                Regenerate
              </>
            )}
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-900/30 border border-red-800 rounded-lg p-4">
          <p className="text-red-400 text-sm">{error}</p>
        </div>
      )}

      <div className="space-y-4">
        {stories.map((story, index) => (
          <div
            key={index}
            className="bg-slate-700 border border-slate-600 rounded-lg overflow-hidden"
          >
            <button
              onClick={() => setExpandedStory(expandedStory === index ? null : index)}
              className="w-full px-6 py-4 text-left hover:bg-slate-600/50 transition-colors flex justify-between items-center"
            >
              <div>
                <h4 className="font-semibold text-white">{story.title}</h4>
                <p className="text-sm text-slate-300 mt-1 line-clamp-2">{story.description}</p>
              </div>
              <div className="text-2xl">
                {expandedStory === index ? '▼' : '▶'}
              </div>
            </button>

            {expandedStory === index && (
              <div className="border-t border-slate-600 px-6 py-4 bg-slate-800 space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-300 mb-2">
                    Description
                  </label>
                  <textarea
                    value={story.description}
                    onChange={(e) => {
                      const updated = [...stories];
                      updated[index].description = e.target.value;
                      setStories(updated);
                    }}
                    className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows={3}
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-300 mb-2">
                    Acceptance Criteria
                  </label>
                  <div className="space-y-2">
                    {story.acceptanceCriteria.map((criterion, idx) => (
                      <input
                        key={idx}
                        type="text"
                        value={criterion}
                        onChange={(e) => {
                          const updated = [...stories];
                          updated[index].acceptanceCriteria[idx] = e.target.value;
                          setStories(updated);
                        }}
                        placeholder={`Criterion ${idx + 1}`}
                        className="w-full px-3 py-2 bg-slate-900 border border-slate-600 rounded text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    ))}
                    <button
                      onClick={() => {
                        const updated = [...stories];
                        updated[index].acceptanceCriteria.push('');
                        setStories(updated);
                      }}
                      className="text-sm text-blue-400 hover:text-blue-300"
                    >
                      + Add Criterion
                    </button>
                  </div>
                </div>

                <div className="flex justify-end">
                  <button
                    onClick={() => handleRemoveStory(index)}
                    className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 transition-colors flex items-center gap-2"
                  >
                    <Trash2 size={16} />
                    Remove Story
                  </button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { ChevronDown, ChevronRight, Plus, BookOpen, Folder, FileText } from 'lucide-react'

interface ContentItem {
  id: string
  title?: string
  content: string
  order: number
}

interface Subject {
  id: string
  title: string
  slug: string
  order: number
  contentItems?: ContentItem[]
}

interface Topic {
  id: string
  title: string
  slug: string
  order: number
  subjects?: Subject[]
}

interface TreeNodeProps {
  item: Topic | Subject | ContentItem
  type: 'topic' | 'subject' | 'content'
  topicSlug?: string
  expanded: boolean
  onToggle: (id: string) => void
  onAdd: (type: 'topic' | 'subject' | 'content', parentId?: string) => void
  level: number
  activeItem?: string
  onSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
}

function TreeNode({
  item,
  type,
  topicSlug,
  expanded,
  onToggle,
  onAdd,
  level,
  activeItem,
  onSelect,
}: TreeNodeProps) {
  const hasChildren =
    (type === 'topic' && (item as Topic).subjects && (item as Topic).subjects!.length > 0) ||
    (type === 'subject' && (item as Subject).contentItems && (item as Subject).contentItems!.length > 0)

  const isActive = activeItem === item.id

  const handleSelect = () => {
    if (onSelect) {
      onSelect(item.id, type)
    }
  }

  let href = ''
  if (type === 'topic') {
    href = `/wiki/${(item as Topic).slug}`
  } else if (type === 'subject') {
    href = `/wiki/${topicSlug}/${(item as Subject).slug}`
  }

  const paddingLeft = level * 12

  return (
    <div className="select-none">
      {/* Node Container */}
      <div className="flex items-center gap-0.5 group" style={{ paddingLeft: `${paddingLeft}px` }}>
        {/* Expand/Collapse Button */}
        {hasChildren ? (
          <button
            onClick={() => onToggle(item.id)}
            className="p-0.5 hover:bg-slate-700 rounded transition-colors"
            aria-label={expanded ? 'Collapse' : 'Expand'}
          >
            {expanded ? (
              <ChevronDown className="w-3.5 h-3.5 text-violet-400" />
            ) : (
              <ChevronRight className="w-3.5 h-3.5 text-slate-500" />
            )}
          </button>
        ) : (
          <div className="w-4" />
        )}

        {/* Node Content */}
        <div className="flex-1 flex items-center gap-1.5 min-w-0">
          {/* Icon */}
          {type === 'topic' && <BookOpen className="w-3.5 h-3.5 text-violet-400 flex-shrink-0" />}
          {type === 'subject' && <Folder className="w-3.5 h-3.5 text-blue-400 flex-shrink-0" />}
          {type === 'content' && <FileText className="w-3.5 h-3.5 text-slate-500 flex-shrink-0" />}

          {/* Link or Label */}
          {href ? (
            <Link
              href={href}
              onClick={handleSelect}
              className={`flex-1 px-1 py-0.5 rounded text-xs truncate transition-colors ${
                isActive
                  ? 'bg-violet-600/30 text-violet-300 font-medium'
                  : 'text-slate-300 hover:text-white hover:bg-slate-700/50'
              }`}
            >
              {item.title}
            </Link>
          ) : (
            <span className="flex-1 px-1 py-0.5 rounded text-xs truncate text-slate-300">
              {item.title}
            </span>
          )}
        </div>

        {/* Add Button (appears on hover) */}
        {type !== 'content' && (
          <button
            onClick={() => onAdd(type === 'topic' ? 'subject' : 'content', item.id)}
            className="p-0.5 opacity-0 group-hover:opacity-100 hover:bg-violet-600 rounded transition-all hover:text-white text-slate-400 flex-shrink-0"
            title={`Add ${type === 'topic' ? 'subject' : 'content'}`}
          >
            <Plus className="w-3 h-3" />
          </button>
        )}
      </div>

      {/* Children */}
      {expanded && hasChildren && (
        <div className="space-y-0">
          {type === 'topic' &&
            (item as Topic).subjects?.map((subject) => (
              <TreeNode
                key={subject.id}
                item={subject}
                type="subject"
                topicSlug={(item as Topic).slug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
          {type === 'subject' &&
            (item as Subject).contentItems?.map((content) => (
              <TreeNode
                key={content.id}
                item={content}
                type="content"
                topicSlug={topicSlug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
        </div>
      )}
    </div>
  )
}

interface WikiSidebarProps {
  onItemSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
  activeItemId?: string
}

export function WikiSidebar({ onItemSelect, activeItemId }: WikiSidebarProps) {
  const [topics, setTopics] = useState<Topic[]>([])
  const [expandedNodes, setExpandedNodes] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadTopics()
  }, [])

  const loadTopics = async () => {
    try {
      const response = await fetch('/api/wiki')
      if (response.ok) {
        const data = await response.json()
        setTopics(data)
      }
    } catch (error) {
      console.error('Failed to load topics:', error)
    } finally {
      setLoading(false)
    }
  }

  const toggleNode = useCallback((id: string) => {
    setExpandedNodes((prev) => {
      const next = new Set(prev)
      if (next.has(id)) {
        next.delete(id)
      } else {
        next.add(id)
      }
      return next
    })
  }, [])

  const handleAdd = useCallback((type: 'topic' | 'subject' | 'content', parentId?: string) => {
    if (type === 'topic') {
      window.location.href = '/wiki'
    } else if (type === 'subject' && parentId) {
      const topic = topics.find((t) => t.id === parentId)
      if (topic) {
        window.location.href = `/wiki/${topic.slug}`
      }
    } else if (type === 'content' && parentId) {
      for (const topic of topics) {
        const subject = topic.subjects?.find((s) => s.id === parentId)
        if (subject) {
          window.location.href = `/wiki/${topic.slug}/${subject.slug}`
          return
        }
      }
    }
  }, [topics])

  if (loading) {
    return (
      <div className="px-4 py-2 text-xs text-slate-400">
        <span className="animate-pulse">Loading wiki...</span>
      </div>
    )
  }

  return (
    <div className="flex flex-col w-full">
      {/* Wiki Header */}
      <div className="px-4 py-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2 min-w-0">
          <BookOpen className="w-4 h-4 text-violet-400 flex-shrink-0" />
          <span className="text-sm font-semibold text-white truncate">Wiki</span>
        </div>
        <button
          onClick={() => handleAdd('topic')}
          className="p-1 hover:bg-violet-600 rounded transition-colors text-slate-400 hover:text-white flex-shrink-0"
          title="Add topic"
        >
          <Plus className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Tree Items */}
      {topics.length === 0 ? (
        <div className="px-4 py-2 text-center">
          <p className="text-xs text-slate-400">No topics</p>
        </div>
      ) : (
        <div className="space-y-0.5 px-2">
          {topics.map((topic) => (
            <TreeNode
              key={topic.id}
              item={topic}
              type="topic"
              expanded={expandedNodes.has(topic.id)}
              onToggle={toggleNode}
              onAdd={handleAdd}
              level={0}
              activeItem={activeItemId}
              onSelect={onItemSelect}
            />
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { ChevronDown, ChevronRight, Plus, BookOpen, Folder, FileText } from 'lucide-react'

interface ContentItem {
  id: string
  title?: string
  content: string
  order: number
}

interface Subject {
  id: string
  title: string
  slug: string
  order: number
  contentItems?: ContentItem[]
}

interface Topic {
  id: string
  title: string
  slug: string
  order: number
  subjects?: Subject[]
}

interface TreeNodeProps {
  item: Topic | Subject | ContentItem
  type: 'topic' | 'subject' | 'content'
  topicSlug?: string
  expanded: boolean
  onToggle: (id: string) => void
  onAdd: (type: 'topic' | 'subject' | 'content', parentId?: string) => void
  level: number
  activeItem?: string
  onSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
}

function TreeNode({
  item,
  type,
  topicSlug,
  expanded,
  onToggle,
  onAdd,
  level,
  activeItem,
  onSelect,
}: TreeNodeProps) {
  const hasChildren =
    (type === 'topic' && (item as Topic).subjects && (item as Topic).subjects!.length > 0) ||
    (type === 'subject' && (item as Subject).contentItems && (item as Subject).contentItems!.length > 0)

  const isActive = activeItem === item.id

  const handleSelect = () => {
    if (onSelect) {
      onSelect(item.id, type)
    }
  }

  // Get display title - use first 20 chars of content if title is missing for content items
  const getDisplayTitle = () => {
    if (item.title) {
      return item.title
    }
    if (type === 'content' && (item as ContentItem).content) {
      return (item as ContentItem).content.substring(0, 20)
    }
    return 'Untitled'
  }

  let href = ''
  if (type === 'topic') {
    href = `/wiki/${(item as Topic).slug}`
  } else if (type === 'subject') {
    href = `/wiki/${topicSlug}/${(item as Subject).slug}`
  }

  const paddingLeft = level * 12

  return (
    <div className="select-none">
      {/* Node Container */}
      <div className="flex items-center gap-0.5 group" style={{ paddingLeft: `${paddingLeft}px` }}>
        {/* Expand/Collapse Button */}
        {hasChildren ? (
          <button
            onClick={() => onToggle(item.id)}
            className="p-0.5 hover:bg-slate-700 rounded transition-colors"
            aria-label={expanded ? 'Collapse' : 'Expand'}
          >
            {expanded ? (
              <ChevronDown className="w-3.5 h-3.5 text-violet-400" />
            ) : (
              <ChevronRight className="w-3.5 h-3.5 text-slate-500" />
            )}
          </button>
        ) : (
          <div className="w-4" />
        )}

        {/* Node Content */}
        <div className="flex-1 flex items-center gap-1.5 min-w-0">
          {/* Icon */}
          {type === 'topic' && <BookOpen className="w-3.5 h-3.5 text-violet-400 flex-shrink-0" />}
          {type === 'subject' && <Folder className="w-3.5 h-3.5 text-blue-400 flex-shrink-0" />}
          {type === 'content' && <FileText className="w-3.5 h-3.5 text-slate-500 flex-shrink-0" />}

           {/* Link or Label */}
           {href ? (
             <Link
               href={href}
               onClick={handleSelect}
               className={`flex-1 px-1 py-0.5 rounded text-xs truncate transition-colors ${
                 isActive
                   ? 'bg-violet-600/30 text-violet-300 font-medium'
                   : 'text-slate-300 hover:text-white hover:bg-slate-700/50'
               }`}
             >
               {getDisplayTitle()}
             </Link>
           ) : (
             <span className="flex-1 px-1 py-0.5 rounded text-xs truncate text-slate-300">
               {getDisplayTitle()}
             </span>
           )}
        </div>

        {/* Add Button (appears on hover) */}
        {type !== 'content' && (
          <button
            onClick={() => onAdd(type === 'topic' ? 'subject' : 'content', item.id)}
            className="p-0.5 opacity-0 group-hover:opacity-100 hover:bg-violet-600 rounded transition-all hover:text-white text-slate-400 flex-shrink-0"
            title={`Add ${type === 'topic' ? 'subject' : 'content'}`}
          >
            <Plus className="w-3 h-3" />
          </button>
        )}
      </div>

      {/* Children */}
      {expanded && hasChildren && (
        <div className="space-y-0">
          {type === 'topic' &&
            (item as Topic).subjects?.map((subject) => (
              <TreeNode
                key={subject.id}
                item={subject}
                type="subject"
                topicSlug={(item as Topic).slug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
          {type === 'subject' &&
            (item as Subject).contentItems?.map((content) => (
              <TreeNode
                key={content.id}
                item={content}
                type="content"
                topicSlug={topicSlug}
                expanded={expanded}
                onToggle={onToggle}
                onAdd={onAdd}
                level={level + 1}
                activeItem={activeItem}
                onSelect={onSelect}
              />
            ))}
        </div>
      )}
    </div>
  )
}

interface WikiSidebarProps {
  onItemSelect?: (id: string, type: 'topic' | 'subject' | 'content') => void
  activeItemId?: string
}

export function WikiSidebar({ onItemSelect, activeItemId }: WikiSidebarProps) {
  const [topics, setTopics] = useState<Topic[]>([])
  const [expandedNodes, setExpandedNodes] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadTopics()
  }, [])

  const loadTopics = async () => {
    try {
      const response = await fetch('/api/wiki')
      if (response.ok) {
        const data = await response.json()
        setTopics(data)
      }
    } catch (error) {
      console.error('Failed to load topics:', error)
    } finally {
      setLoading(false)
    }
  }

  const toggleNode = useCallback((id: string) => {
    setExpandedNodes((prev) => {
      const next = new Set(prev)
      if (next.has(id)) {
        next.delete(id)
      } else {
        next.add(id)
      }
      return next
    })
  }, [])

  const handleAdd = useCallback((type: 'topic' | 'subject' | 'content', parentId?: string) => {
    if (type === 'topic') {
      window.location.href = '/wiki'
    } else if (type === 'subject' && parentId) {
      const topic = topics.find((t) => t.id === parentId)
      if (topic) {
        window.location.href = `/wiki/${topic.slug}`
      }
    } else if (type === 'content' && parentId) {
      for (const topic of topics) {
        const subject = topic.subjects?.find((s) => s.id === parentId)
        if (subject) {
          window.location.href = `/wiki/${topic.slug}/${subject.slug}`
          return
        }
      }
    }
  }, [topics])

  if (loading) {
    return (
      <div className="px-4 py-2 text-xs text-slate-400">
        <span className="animate-pulse">Loading wiki...</span>
      </div>
    )
  }

  return (
    <div className="flex flex-col w-full">
      {/* Wiki Header */}
      <div className="px-4 py-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2 min-w-0">
          <BookOpen className="w-4 h-4 text-violet-400 flex-shrink-0" />
          <span className="text-sm font-semibold text-white truncate">Wiki</span>
        </div>
        <button
          onClick={() => handleAdd('topic')}
          className="p-1 hover:bg-violet-600 rounded transition-colors text-slate-400 hover:text-white flex-shrink-0"
          title="Add topic"
        >
          <Plus className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Tree Items */}
      {topics.length === 0 ? (
        <div className="px-4 py-2 text-center">
          <p className="text-xs text-slate-400">No topics</p>
        </div>
      ) : (
        <div className="space-y-0.5 px-2">
          {topics.map((topic) => (
            <TreeNode
              key={topic.id}
              item={topic}
              type="topic"
              expanded={expandedNodes.has(topic.id)}
              onToggle={toggleNode}
              onAdd={handleAdd}
              level={0}
              activeItem={activeItemId}
              onSelect={onItemSelect}
            />
          ))}
        </div>
      )}
    </div>
  )
}
